import { describe, it, expect, vi, beforeEach } from 'vitest';

import * as utils from '../src/utils.js';
import { renderMarkdown } from '../src/utils/markdown.js';

describe('renderMarkdown', () => {
  beforeEach(() => {
    vi.spyOn(utils, 'getTerminalWidth').mockReturnValue(80);
  });

  it('renders basic markdown text correctly', () => {
    const markdown = 'Hello world';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines[0]?.startsWith('┌')).toBe(true);
    expect(lines[1]?.includes('Hello world')).toBe(true);
    expect(lines[lines.length - 1]?.startsWith('└')).toBe(true);
  });

  it('renders headings with proper formatting', () => {
    const markdown = '# Heading 1\n\nSome content';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('Heading 1'))).toContain('\u001b[1m\u001b[32m');
  });

  it('renders paragraphs with proper spacing', () => {
    const markdown = 'First paragraph.\n\nSecond paragraph.';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    const firstParaIndex = lines.findIndex((line) => line.includes('First paragraph'));
    const secondParaIndex = lines.findIndex((line) => line.includes('Second paragraph'));

    expect(secondParaIndex - firstParaIndex).toBeGreaterThan(1);
  });

  it('renders unordered lists with bullet points', () => {
    const markdown = '- Item 1\n- Item 2';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('•') && line.includes('Item 1'))).toBeTruthy();
    expect(lines.find((line) => line.includes('•') && line.includes('Item 2'))).toBeTruthy();
  });

  it('renders ordered lists with numbers', () => {
    const markdown = '1. First item\n2. Second item';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('1.') && line.includes('First item'))).toBeTruthy();
    expect(lines.find((line) => line.includes('2.') && line.includes('Second item'))).toBeTruthy();
  });

  it('handles strong/bold text formatting', () => {
    const markdown = 'This is **bold** text';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    const contentLine = lines.find((line) => line.includes('This is'));
    expect(contentLine).toContain('\u001b[1m');
  });

  it('handles emphasis/italic text formatting', () => {
    const markdown = 'This is *italic* text';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    const contentLine = lines.find((line) => line.includes('This is'));
    expect(contentLine).toContain('\u001b[3m');
  });

  it('handles code blocks', () => {
    const markdown = '```\nconst x = 1;\n```';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('const x = 1;'))).toBeTruthy();
  });

  it('handles blockquotes', () => {
    const markdown = '> This is a quote';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(
      lines.find((line) => utils.getVisibleString(line).includes('> This is a quote'))
    ).toBeTruthy();
  });

  it('handles thematic breaks (horizontal rules)', () => {
    const markdown = 'Before\n\n---\n\nAfter';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('---'))).toBeTruthy();
  });

  it('handles images with alt text', () => {
    const markdown = '![Alt text](image.jpg)';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('[Image: Alt text]'))).toBeTruthy();
  });

  it('handles inline code', () => {
    const markdown = 'Use the `console.log()` function';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines.find((line) => line.includes('console.log()'))).toBeTruthy();
  });

  it('handles long text that needs wrapping', () => {
    const longText =
      'This is a very long paragraph that should be wrapped because it exceeds the terminal width. The wrapping should ensure that no line is too long for display purposes.';
    const result = renderMarkdown(longText);

    const lines = result
      .split('\n')
      .filter((line) => line !== '' && !line.startsWith('┌') && !line.startsWith('└'));

    lines.forEach((line) => {
      const cleanLine = line.replace(/^\│\s|\s\│$/g, '').replace(/\u001b\[.*?m/g, '');
      expect(cleanLine.length).toBeLessThanOrEqual(76);
    });

    expect(lines.length).toBeGreaterThan(1);
  });

  it('handles complex nested markdown', () => {
    const complexMarkdown = `# Complex Example

This is a paragraph with **bold** and *italic* text.

## Subheading

- List item 1
- List item with **bold** text
- List item with \`code\`

> A blockquote with some *emphasized* text
`;

    const result = renderMarkdown(complexMarkdown);

    expect(result).toContain('Complex Example');
    expect(result).toContain('Subheading');
    expect(result).toContain('List item 1');
  });

  it('handles empty input', () => {
    const markdown = '';
    const result = renderMarkdown(markdown);

    const lines = result.split('\n');
    expect(lines[0]?.startsWith('┌')).toBe(true);
    expect(lines[lines.length - 1]?.startsWith('└')).toBe(true);
  });
});
